 327 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 328 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 329 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
