 332 |         if (op.ai_strategy === "line_insert" && op.anchor_line) {
 333 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 334 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 335 |             const payload = op.replace_with || op.content || "";
 336 |             if (op.action === "insert_after") {
